import Phaser from 'phaser'; 
import Controls from '../utils/Controls'

export default class Hero extends Phaser.Physics.Arcade.Sprite
{
    private vel = 200;
    private damaged = false;
    
    constructor(scene: Phaser.Scene, x: number, y: number, texture: string, frame?: string | number)
    {
        super(scene, x, y, texture, frame);
        this.scene.physics.world.enable(this);
        this.body.setSize(16, 16)
        this.body.setOffset(15, 15)
    }



    update(cursors: Controls)
    {
        if(cursors.DOWN.isDown && !(cursors.KEY5.isDown || cursors.KEY6.isDown || cursors.KEY7.isDown || cursors.KEY8.isDown))
        {
            this.body.setSize(16, 16)
            this.body.setOffset(15, 15)
            this.anims.play('hero-run-down', true);
            this.setVelocity(0, this.vel);           
        }

        else if(cursors.UP.isDown && !(cursors.KEY5.isDown || cursors.KEY6.isDown || cursors.KEY7.isDown || cursors.KEY8.isDown))
        {
            this.body.setSize(16, 16)
            this.body.setOffset(15, 15)
            this.anims.play('hero-run-up', true);
            this.setVelocity(0, -this.vel);
        }

        else if(cursors.RIGHT.isDown && !(cursors.KEY5.isDown || cursors.KEY6.isDown || cursors.KEY7.isDown || cursors.KEY8.isDown))
        {
            this.body.setSize(16, 16)
            this.body.setOffset(15, 15)
            this.anims.play('hero-run-right', true);
            this.setVelocity(this.vel, 0);       
        }

        else if(cursors.LEFT.isDown && !(cursors.KEY5.isDown || cursors.KEY6.isDown || cursors.KEY7.isDown || cursors.KEY8.isDown))
        {
            this.body.setSize(16, 16)
            this.body.setOffset(15, 15)
            this.anims.play('hero-run-left', true);
            this.setVelocity(-this.vel, 0);
        }

        else if(cursors.KEY5.isDown)
        {   
            this.body.setSize(16, 28);
            this.body.setOffset(15, 3);
            this.setVelocity(0, 0)
            this.anims.play('hero-attack-up', true)
            
        }

        else if(cursors.KEY6.isDown)
        {   
            this.body.setSize(16, 28);
            this.body.setOffset(15, 15);
            this.setVelocity(0, 0)
            this.anims.play('hero-attack-down', true)
        }

        else if(cursors.KEY7.isDown)
        {   
            this.body.setSize(28, 14);
            this.body.setOffset(17, 16);
            this.setVelocity(0, 0)
            this.anims.play('hero-attack-right', true)
        }

        else if(cursors.KEY8.isDown)
        {   
            this.body.setSize(28, 14);
            this.body.setOffset(1, 16);
            this.setVelocity(0, 0)
            this.anims.play('hero-attack-left', true)
        }

        else
        {
            this.body.setSize(16, 16)
            this.body.setOffset(15, 15)
            this.setVelocity(0, 0)
            this.anims.play('hero-idle', true)
            
        }
   
    }
}
